- 6+ elements: 0 points

FACTOR 5: Curiosity / Visual Hook (max 10 points)
- Full (10): Clear visual question / implied incomplete story
- Partial (5): Mildly interesting
- Zero (0): Generic, no intrigue

FACTOR 6: Niche Relevance (max 15 points)
- Full (15): Topic instantly clear without reading title
- Partial (7): Inferable with effort
- Zero (0): Could be any video

FACTOR 7: Brand / Style Consistency (max 5 points)
- Full (5): Matches channel visual identity
- If "Not specified": default to 3 points (neutral)
- Zero (0): Clearly inconsistent

CALCULATE:
total_score = sum of all 7 factors (cap at 100)
decision = "accept" if total_score >= 75
         = "review" if total_score >= 60
         = "regenerate" if total_score < 60

If decision is "regenerate" or "review", include an improvement_prompt — a rewritten Fal.ai Seedream 4.0 image generation prompt that specifically addresses the failing factors.

Return ONLY this JSON (no other text):
{
  "thumbnail_ctr_score": <integer 0-100>,
  "decision": "<accept|review|regenerate>",
  "score_breakdown": {
    "face_emotion": <int>,
    "text_readability": <int>,
    "color_contrast": <int>,
    "visual_complexity": <int>,
    "curiosity_hook": <int>,
    "niche_relevance": <int>,
    "brand_consistency": <int>
  },
  "improvement_suggestions": ["<string>", "<string>"],
  "improvement_prompt": "<string — only if regenerate or review>",
  "primary_weakness": "<single most impactful thing to fix>"
}`;

const scoreStart = Date.now();
const visionRes = await callClaudeVision(thumbUrl, prompt, 1500, 'opus_vision_thumbnail', 4);

const parsed = visionRes.ok ? parseJson(visionRes.text) : null;

function clampScore(n, max) { const v = Number(n) || 0; return Math.max(0, Math.min(max, Math.round(v))); }

let breakdown = parsed?.score_breakdown || {};
breakdown = {
  face_emotion: clampScore(breakdown.face_emotion, 20),
  text_readability: clampScore(breakdown.text_readability, 20),
  color_contrast: clampScore(breakdown.color_contrast, 15),
  visual_complexity: clampScore(breakdown.visual_complexity, 15),
  curiosity_hook: clampScore(breakdown.curiosity_hook, 10),
  niche_relevance: clampScore(breakdown.niche_relevance, 15),
  brand_consistency: clampScore(breakdown.brand_consistency, 5)
};

// Authoritative score = sum of clamped breakdown (prevents Claude drift between total + breakdown)
const authoritativeScore = Object.values(breakdown).reduce((a, b) => a + b, 0);

// Derive decision from authoritative score (ignore Claude's decision if it contradicts)
let decision;
if (authoritativeScore >= 75) decision = 'accept';
else if (authoritativeScore >= 60) decision = 'review';
else decision = 'regenerate';

const improvementSuggestions = Array.isArray(parsed?.improvement_suggestions) ? parsed.improvement_suggestions.slice(0, 6).map(String) : [];
const improvementPrompt = String(parsed?.improvement_prompt || '').slice(0, 2000);
const primaryWeakness = String(parsed?.primary_weakness || '').slice(0, 500);

const scored = !!parsed;
const costUsd = scored ? 0.08 : 0;

return [{
  json: {
    ...data,
    score: {
      thumbnail_ctr_score: authoritativeScore,
      decision,
      score_breakdown: breakdown,
      improvement_suggestions: improvementSuggestions,
      improvement_prompt: improvementPrompt,
      primary_weakness: primaryWeakness
    },
    vision_ok: scored,
    vision_error: scored ? null : (visionRes.error || 'parse_failed'),
    vision_duration_ms: Date.now() - scoreStart,
    vision_cost_usd: costUsd
  }
}];

// Persist score to topics, append to regen_history. If decision='regenerate' AND attempts<3,
// fire-and-forget call to WF_THUMBNAIL_GENERATE webhook with improvement_prompt (simpler than
// Execute Workflow nested wait — re-entry flows back through /webhook/thumbnail/score).
// If decision='review', DO NOT auto-regen — leave for Gate 3.
// If decision='accept' OR attempts>=3, finalize.

const data = $input.first().json;
if (data.success === false) return [{ json: data }];
if (data.skipped) return [{ json: data }];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};
const n8nBase = $env.N8N_WEBHOOK_BASE;
const dashToken = $env.DASHBOARD_API_TOKEN;

const topicId = data.topic_id;
const projectId = data.project_id;
const score = data.score;
const thumbnailUrl = data.thumbnail_url;
const attempts = Number(data.attempts || 0);
const history = Array.isArray(data.history) ? data.history.slice() : [];
const nowIso = new Date().toISOString();

// Append new attempt to history (attempt # is 1-indexed)
history.push({
  attempt: attempts + 1,
  thumbnail_url: thumbnailUrl,
  score: score.thumbnail_ctr_score,
  decision: score.decision,
  primary_weakness: score.primary_weakness,
  scored_at: nowIso
});

// Determine finalization:
// - accept OR attempts+1 >= 3 (meaning this is the 3rd+ attempt) -> finalize with current decision
// - review -> finalize with review (await human)
// - regenerate AND attempts+1 < 3 -> dispatch regen (attempts increments on next entry)
const isFinal = (score.decision === 'accept') || (score.decision === 'review') || (attempts + 1 >= 3);
const shouldRegen = (score.decision === 'regenerate') && ((attempts + 1) < 3);

// If we're at attempt 3 with regenerate decision, force-accept with a note
let finalDecision = score.decision;
if (!isFinal && !shouldRegen) {
  // Edge case safety — should not hit
  finalDecision = 'review';
}
if (score.decision === 'regenerate' && !shouldRegen) {
  finalDecision = 'accept'; // exhausted retries
}

const patch = {
  thumbnail_ctr_score: score.thumbnail_ctr_score,
  thumbnail_score_breakdown: score.score_breakdown,
  thumbnail_decision: finalDecision,
  thumbnail_primary_weakness: score.primary_weakness || null,
  thumbnail_improvement_suggestions: score.improvement_suggestions || [],
  thumbnail_regen_attempts: attempts + 1,
  thumbnail_regen_history: history,
  thumbnail_scored_at: nowIso
};

let patchError = null;
try {
  const res = await fetch(`${supabaseUrl}/rest/v1/topics?id=eq.${topicId}`, {
    method: 'PATCH',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify(patch)
  });
  if (!res.ok) patchError = `PATCH failed: HTTP ${res.status}: ${(await res.text()).slice(0, 200)}`;
} catch (e) {
  patchError = e.message;
}

// Fire-and-forget regen dispatch
let regenDispatched = false;
let regenError = null;
if (shouldRegen && !patchError && score.improvement_prompt) {
  try {
    // Call WF_THUMBNAIL_GENERATE webhook. That workflow will:
    //   1. Generate a new thumbnail via Seedream 4.0 using improvement_prompt
    //   2. Upload to Drive
    //   3. POST back to /webhook/thumbnail/score with { topic_id, thumbnail_url: new_url }
    // We do not await the full regen — dispatch and return current score to caller.
    const regenRes = await fetch(`${n8nBase}/thumbnail/generate`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${dashToken}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        topic_id: topicId,
        improvement_prompt: score.improvement_prompt,
        attempt_count: attempts + 1,
        score_callback: `${n8nBase}/thumbnail/score`
      })
    });
    regenDispatched = regenRes.ok;
    if (!regenRes.ok) regenError = `Regen dispatch HTTP ${regenRes.status}`;
  } catch (e) {
    regenError = e.message;
  }
}

// production_logs
try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: projectId,
      topic_id: topicId,
      stage: 'thumbnail_score',
      scene_number: null,
      action: shouldRegen ? 'opus_vision_regen_dispatched' : 'opus_vision_7factor',
      status: patchError ? 'partial' : (data.vision_ok ? 'success' : 'fallback'),
      duration_ms: data.vision_duration_ms || 0,
      cost_usd: data.vision_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) { }

return [{
  json: {
    success: !patchError,
    topic_id: topicId,
    project_id: projectId,
    thumbnail_url: thumbnailUrl,
    thumbnail_ctr_score: score.thumbnail_ctr_score,
    thumbnail_decision: finalDecision,
    thumbnail_score_breakdown: score.score_breakdown,
    thumbnail_primary_weakness: score.primary_weakness,
    thumbnail_improvement_suggestions: score.improvement_suggestions,
    thumbnail_improvement_prompt: shouldRegen ? score.improvement_prompt : null,
    thumbnail_regen_attempts: attempts + 1,
    thumbnail_scored_at: nowIso,
    regen_dispatched: regenDispatched,
    regen_error: regenError,
    vision_ok: data.vision_ok,
    vision_cost_usd: data.vision_cost_usd,
    patch_error: patchError,
    http_status: patchError ? 500 : 200,
    via_webhook: data.via_webhook
  }
}];
